    "html": "<form action=\"\" class=\"form\">\n    <p>\n        Welcome,<span>sign in to continue</span>\n    </p>\n    <button class=\"oauthButton\">\n                    <svg class=\"icon\" viewBox=\"0 0 24 24\">\n            <path d=\"M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z\" fill=\"#4285F4\"></path>\n            <path d=\"M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z\" fill=\"#34A853\"></path>\n            <path d=\"M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z\" fill=\"#FBBC05\"></path>\n            <path d=\"M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z\" fill=\"#EA4335\"></path>\n            <path d=\"M1 1h22v22H1z\" fill=\"none\"></path>\n        </svg>\n                    Continue with Google\n                </button>\n    <button class=\"oauthButton\">\n                    <svg class=\"icon\" viewBox=\"0 0 24 24\">\n            <path d=\"M12 .297c-6.63 0-12 5.373-12 12 0 5.303 3.438 9.8 8.205 11.385.6.113.82-.258.82-.577 0-.285-.01-1.04-.015-2.04-3.338.724-4.042-1.61-4.042-1.61C4.422 18.07 3.633 17.7 3.633 17.7c-1.087-.744.084-.729.084-.729 1.205.084 1.838 1.236 1.838 1.236 1.07 1.835 2.809 1.305 3.495.998.108-.776.417-1.305.76-1.605-2.665-.3-5.466-1.332-5.466-5.93 0-1.31.465-2.38 1.235-3.22-.135-.303-.54-1.523.105-3.176 0 0 1.005-.322 3.3 1.23.96-.267 1.98-.399 3-.405 1.02.006 2.04.138 3 .405 2.28-1.552 3.285-1.23 3.285-1.23.645 1.653.24 2.873.12 3.176.765.84 1.23 1.91 1.23 3.22 0 4.61-2.805 5.625-5.475 5.92.42.36.81 1.096.81 2.22 0 1.606-.015 2.896-.015 3.286 0 .315.21.69.825.57C20.565 22.092 24 17.592 24 12.297c0-6.627-5.373-12-12-12\"></path>\n        </svg>\n                    Continue with Github\n                </button>\n    <div class=\"separator\">\n        <div></div>\n        <span>OR</span>\n        <div></div>\n    </div>\n    <input type=\"email\" placeholder=\"Email\" name=\"email\">\n    <button class=\"oauthButton\">\n                    Continue\n                    <svg class=\"icon\" xmlns=\"http://www.w3.org/2000/svg\" width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"m6 17 5-5-5-5\"></path><path d=\"m13 17 5-5-5-5\"></path></svg>\n                </button>\n</form>",
    "css": "/* From Uiverse.io by D3OXY - Source: https://uiverse.io/andrew-demchenk0/little-treefrog-9 - Tags: form, github, google, login form, sign up form, card animation, card hover, 3d card, email card, oauth */\n/* DEOXY Was Here */\n.form {\n  --background: #d3d3d3;\n  --input-focus: #2d8cf0;\n  --font-color: #323232;\n  --font-color-sub: #666;\n  --bg-color: #fff;\n  --main-color: #323232;\n  padding: 20px;\n  background: var(--background);\n  display: flex;\n  flex-direction: column;\n  align-items: flex-start;\n  justify-content: center;\n  gap: 20px;\n  border-radius: 5px;\n  border: 2px solid var(--main-color);\n  box-shadow: 4px 4px var(--main-color);\n}\n\n.form > p {\n  font-family: var(--font-DelaGothicOne);\n  color: var(--font-color);\n  font-weight: 700;\n  font-size: 20px;\n  margin-bottom: 15px;\n  display: flex;\n  flex-direction: column;\n}\n\n.form > p > span {\n  font-family: var(--font-SpaceMono);\n  color: var(--font-color-sub);\n  font-weight: 600;\n  font-size: 17px;\n}\n\n.separator {\n  width: 100%;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  gap: 5px;\n}\n\n.separator > div {\n  width: 100px;\n  height: 3px;\n  border-radius: 5px;\n  background-color: var(--font-color-sub);\n}\n\n.separator > span {\n  color: var(--font-color);\n  font-family: var(--font-SpaceMono);\n  font-weight: 600;\n}\n\n.oauthButton {\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  gap: 5px;\n    /* margin: 50px auto 0 auto; */\n  padding: auto 15px 15px auto;\n  width: 250px;\n  height: 40px;\n  border-radius: 5px;\n  border: 2px solid var(--main-color);\n  background-color: var(--bg-color);\n  box-shadow: 4px 4px var(--main-color);\n  font-size: 16px;\n  font-weight: 600;\n  color: var(--font-color);\n  cursor: pointer;\n  transition: all 250ms;\n  position: relative;\n  overflow: hidden;\n  z-index: 1;\n}\n\n.oauthButton::before {\n  content: \"\";\n  position: absolute;\n  top: 0;\n  left: 0;\n  height: 100%;\n  width: 0;\n  background-color: #212121;\n  z-index: -1;\n  -webkit-box-shadow: 4px 8px 19px -3px rgba(0, 0, 0, 0.27);\n  box-shadow: 4px 8px 19px -3px rgba(0, 0, 0, 0.27);\n  transition: all 250ms;\n}\n\n.oauthButton:hover {\n  color: #e8e8e8;\n}\n\n.oauthButton:hover::before {\n  width: 100%;\n}\n\n.form > input {\n  width: 250px;\n  height: 40px;\n  border-radius: 5px;\n  border: 2px solid var(--main-color);\n  background-color: var(--bg-color);\n  box-shadow: 4px 4px var(--main-color);\n  font-size: 15px;\n  font-weight: 600;\n  color: var(--font-color);\n  padding: 5px 10px;\n  outline: none;\n}\n\n.icon {\n  width: 1.5rem;\n  height: 1.5rem;\n}"
