    "css": "/* From Uiverse.io by Galahhad - Tags: form */\n.form-container__sign-app-buttons svg {\n  width: 22px;\n  height: auto;\n}\n\n.google svg {\n  width: 18px;\n  height: auto;\n}\n\n.form-container {\n  min-width: 350px;\n  box-sizing: border-box;\n  font-family: sans-serif;\n  color: #4b4b4b;\n  min-height: 20px;\n  padding: 19px;\n  margin-bottom: 20px;\n  background-color: #f5f5f5;\n}\n\n.form-container:focus-within:not(:focus) {\n  box-shadow: 0 0 6px 3px #caedff;\n  -webkit-box-shadow: 0 0 6px 3px #caedff;\n  outline: 1px solid #97dbff;\n}\n\n.form-container p {\n  font-size: 14px;\n  font-weight: bold;\n  margin-bottom: 14px;\n}\n\n.top-line {\n  padding-top: 12px;\n}\n\n.form-container__form {\n  display: flex;\n  flex-direction: column;\n  row-gap: 16px;\n}\n\n.form-container__form input {\n  height: 31px;\n  border: 1px solid #d9d9d9;\n  padding: 4px;\n  font-size: 14px;\n  line-height: 1.65;\n  -webkit-box-shadow: inset 0 1px 1px rgba(0, 0, 0, 0.075);\n  box-shadow: inset 0 1px 1px rgba(0, 0, 0, 0.075);\n  -webkit-transition: border-color ease-in-out .15s, box-shadow ease-in-out .15s;\n  -o-transition: border-color ease-in-out .15s, box-shadow ease-in-out .15s;\n  transition: border-color ease-in-out .15s, box-shadow ease-in-out .15s;\n}\n\n.form-container__form input:focus {\n  border-color: #00a6fd;\n  outline: 0;\n  box-shadow: none;\n}\n\n.form-container__register-buttons {\n  display: flex;\n  column-gap: 10px;\n}\n\n.form-container__sign {\n  padding: 8px 20px;\n  font-size: 14px;\n  line-height: 1.65;\n  border-radius: 20px;\n  width: 110px;\n  white-space: nowrap;\n  background-color: #00a6fd;\n  border: none;\n  color: white;\n  font-weight: bold;\n  cursor: pointer;\n}\n\n.form-container__sign:first-child:active,\n.form-container__sign:first-child:hover {\n  background-color: #0099e9;\n}\n\n.form-container__sign:focus {\n  outline-offset: -2px;\n  outline: none;\n  -webkit-box-shadow: inset 0 0 3px 1px #97dbff;\n  box-shadow: inset 0 0 3px 1px #97dbff;\n}\n\n.forgot {\n  width: auto;\n  padding: 8px 0;\n  background: none;\n  font-weight: 400;\n  color: #428bca;\n  text-decoration: none;\n}\n\n.forgot:hover {\n  text-decoration: underline;\n  color: #4c9dd0;\n}\n\n.form-container__header {\n  padding-bottom: 16px;\n}\n\n.form-container__footer {\n  padding-top: 12px;\n  border-top: 1px solid #cacaca;\n}\n\n.form-container__sign-app-buttons {\n  display: flex;\n  column-gap: 24px;\n}\n\n.form-container__sign-app-buttons button:not(:first-child) {\n  border: none;\n  background: none;\n  cursor: pointer;\n  position: relative;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n\n.form-container__sign-app-buttons button:not(:first-child)::before {\n  position: absolute;\n  content: '';\n  width: 120%;\n  height: 2px;\n  background: rgb(187, 187, 187);\n  bottom: 0;\n  opacity: 0;\n}\n\n.form-container__sign-app-buttons button:not(:first-child):hover::before {\n  opacity: 1;\n  transition: 1s;\n}\n\n.form-container__sign-app-buttons button:not(:first-child):focus::before {\n  opacity: 1;\n  background-color: #4b4b4b;\n}\n\n.form-container__sign-app-buttons button:first-child {\n  justify-content: center;\n  min-width: 110px;\n  height: 40px;\n  border: none;\n  background: white;\n  border-radius: 2px;\n  box-shadow: 0 0 1px rgba(0, 0, 0, 0.1), 0 1px 1px #b7b7b7;\n  display: flex;\n  align-items: center;\n  color: #4b4b4b;\n  font-size: 13px;\n  column-gap: 15px;\n  cursor: pointer;\n}\n\n.form-container__sign-app-buttons button:first-child:active {\n  background: #eeeeee;\n}\n\n.form-container__sign-app-buttons button:first-child:focus:not(:active) {\n  outline: none;\n  -webkit-box-shadow: inset 0 0 3px 1px #97dbff;\n  box-shadow: inset 0 0 3px 1px #97dbff;\n}"
