    "animationLevel": "high",
    "html": "<div class=\"container\">\n  <form class=\"form\" action=\"\">\n    <p class=\"title\">Login Form</p>\n    <input placeholder=\"Username\" class=\"username input\" type=\"text\" />\n    <input placeholder=\"Password\" class=\"password input\" type=\"password\" />\n    <button class=\"btn\" type=\"submit\">Login</button>\n  </form>\n</div>",
    "css": "/* From Uiverse.io by HoseinParvaresh  - Tags: form, login , login form, dark, rounded, input, button, orange, gradient, minimalistic, password, form, username, centered, login */\n::selection {\n  background-color: gray;\n}\n\n.container {\n  margin: 0 auto;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n\n.form {\n  width: 400px;\n  height: 400px;\n  background-image: linear-gradient(to bottom, #424242, #212121);\n  display: flex;\n  align-items: center;\n  flex-direction: column;\n  border-radius: 0.5rem;\n}\n\n.title {\n  color: wheat;\n  margin: 3rem 0;\n  font-size: 2rem;\n}\n\n.input {\n  margin: 0.5rem 0;\n  padding: 1rem 0.5rem;\n  width: 20rem;\n  background-color: inherit;\n  color: wheat;\n  border: none;\n  outline: none;\n  border-bottom: 1px solid wheat;\n  transition: all 400ms;\n}\n.input:hover {\n  background-color: #424242;\n  border: none;\n  border-radius: 0.5rem;\n}\n.btn {\n  height: 3rem;\n  width: 20rem;\n  margin-top: 3rem;\n  background-color: wheat;\n  border-radius: 0.5rem;\n  border: none;\n  font-size: 1.2rem;\n  transition: all 400ms;\n  cursor: pointer;\n  box-shadow:\n    0 0 10px antiquewhite,\n    0 0 10px antiquewhite;\n}\n.btn:hover {\n  background-color: antiquewhite;\n  box-shadow: none;\n}"
