    "css": "/* From Uiverse.io by JohnnyCSilva - Tags: login, login form, account */\n.form {\n  display: flex;\n  flex-direction: column;\n  gap: 10px;\n  background-color: #ffffff;\n  padding: 30px;\n  width: 450px;\n  border-radius: 20px;\n  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, 'Open Sans', 'Helvetica Neue', sans-serif;\n}\n\n::placeholder {\n  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, 'Open Sans', 'Helvetica Neue', sans-serif;\n}\n\n.form button {\n  align-self: flex-end;\n}\n\n.flex-column > label {\n  color: #151717;\n  font-weight: 600;\n}\n\n.inputForm {\n  border: 1.5px solid #ecedec;\n  border-radius: 10px;\n  height: 50px;\n  display: flex;\n  align-items: center;\n  padding-left: 10px;\n  transition: 0.2s ease-in-out;\n}\n\n.input {\n  margin-left: 10px;\n  border-radius: 10px;\n  border: none;\n  width: 100%;\n  height: 100%;\n}\n\n.input:focus {\n  outline: none;\n}\n\n.inputForm:focus-within {\n  border: 1.5px solid #2d79f3;\n}\n\n.flex-row {\n  display: flex;\n  flex-direction: row;\n  align-items: center;\n  gap: 10px;\n  justify-content: space-between;\n}\n\n.flex-row > div > label {\n  font-size: 14px;\n  color: black;\n  font-weight: 400;\n}\n\n.span {\n  font-size: 14px;\n  margin-left: 5px;\n  color: #2d79f3;\n  font-weight: 500;\n  cursor: pointer;\n}\n\n.button-submit {\n  margin: 20px 0 10px 0;\n  background-color: #151717;\n  border: none;\n  color: white;\n  font-size: 15px;\n  font-weight: 500;\n  border-radius: 10px;\n  height: 50px;\n  width: 100%;\n  cursor: pointer;\n}\n\n.p {\n  text-align: center;\n  color: black;\n  font-size: 14px;\n  margin: 5px 0;\n}\n\n.btn {\n  margin-top: 10px;\n  width: 100%;\n  height: 50px;\n  border-radius: 10px;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  font-weight: 500;\n  gap: 10px;\n  border: 1px solid #ededef;\n  background-color: white;\n  cursor: pointer;\n  transition: 0.2s ease-in-out;\n}\n\n.btn:hover {\n  border: 1px solid #2d79f3;\n  ;\n}"
