    "css": "/* From Uiverse.io by KhelVers  - Tags: form, input, login  */\n#Container {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: flex-end;\n  height: 100%;\n}\n\n#rays {\n  z-index: 2;\n  position: relative;\n  bottom: -1.5em;\n  animation: rays 2s ease-in-out infinite;\n}\n\n.form {\n  position: relative;\n  top: 5em;\n  padding: 4%;\n  z-index: 3;\n  display: flex;\n  flex-direction: column;\n  border-radius: 0.5rem;\n  border: 4px solid #fff;\n  background: rgba(0, 255, 240, 0.52);\n  box-shadow: 0px 0px 64px 0px #82e1ff inset, 0px 0px 16px #a8fffaa6;\n  backdrop-filter: blur(3.5px);\n  gap: 1em;\n  animation: float 2s ease-in-out infinite;\n}\n\n#login-lable {\n  text-align: center;\n  color: white;\n  font-size: 2rem;\n  font-weight: 600;\n  letter-spacing: 8px;\n  text-shadow: 0px 0px 16px rgb(243, 243, 243);\n}\n\n.form-content {\n  height: 3em;\n  padding: 1px 8px;\n  color: white;\n  text-decoration: none;\n  letter-spacing: 1px;\n  font-weight: bold;\n  border-radius: 6px;\n  border: 2px solid #fff;\n  background: rgba(139, 255, 247, 0.486);\n  box-shadow: 0px 0px 1px 3px #9ee5e3 inset, 0px 4px 4px 0px #181a6040;\n  text-shadow: 0px 1px 4px rgb(243, 243, 243);\n}\n\n.form-content:focus-visible {\n  outline: none;\n  text-decoration: none;\n  background: rgba(139, 189, 255, 0.59);\n  box-shadow: 0px 0px 1px 4px #9ee5e3;\n}\n\n.form-content:hover {\n  background: rgba(139, 189, 255, 0.59);\n}\n\n::placeholder {\n  font-weight: 300;\n  color: white;\n  letter-spacing: 0.1rem;\n  text-shadow: 0px 1px 5px rgb(66, 66, 66);\n}\n\n.form button {\n  cursor: pointer;\n  height: 3.5rem;\n  padding: 0%;\n  color: white;\n  font-size: 1.5em;\n  letter-spacing: 0.3rem;\n  border: 2px solid white;\n  background: linear-gradient(144deg, #9c11ffce, #2000eeb6 50%, #15efffbb);\n}\n\n.form button:hover {\n  position: relative;\n  bottom: 4px;\n  background: linear-gradient(144deg, #9c11ff, #2000ee 50%, #15fff3);\n  box-shadow: 0px 0px 2px 2px #ffffff;\n}\n\n@keyframes float {\n  0% {\n    position: relative;\n  }\n\n  50% {\n    top: 50px;\n  }\n\n  100% {\n    position: relative;\n  }\n}\n\n@keyframes rays {\n  0% {\n    opacity: 0.6;\n  }\n\n  50% {\n    opacity: 1;\n  }\n\n  100% {\n    opacity: 0.6;\n  }\n}"
