    "html": "<div class=\"login-container\">\n    <div class=\"login-header\">\n      <div>Login</div>\n    </div>\n    <input type=\"text\" class=\"login-input\" placeholder=\"Username\" id=\"username\">\n    <input type=\"password\" class=\"login-input\" placeholder=\"Password (Min-8, Max-15)\" id=\"password\" maxlength=\"15\" minlength=\"8\">\n    <button class=\"login-button\" id=\"login-button\">Login</button>\n  </div>",
    "css": "/* From Uiverse.io by KhelVers - Tags: form, login form, log in, 3d form , 3d login form, standard, luxary */\n.login-container {\n  width: 300px;\n  padding: 20px;\n  background: #fff;\n  border-radius: 8px;\n  box-shadow: 0px 10px 20px rgba(0, 0, 0, 0.1), 0px 0px 0px 3px #3498db, inset 0px 0px 10px rgba(0, 0, 0, 0.1);\n}\n\n.login-header {\n  font-size: x-large;\n  font-weight: 600;\n  text-align: center;\n  margin-bottom: 20px;\n}\n\n.login-header h1 {\n  color: #333;\n  font-size: 24px;\n}\n\n.login-input {\n  width: 100%;\n  padding: 10px;\n  margin-bottom: 15px;\n  border: none;\n  background: #f5f5f5;\n  border-radius: 4px;\n  box-shadow: inset 0px 1px 3px rgba(0, 0, 0, 0.2);\n}\n\n.login-button {\n  width: 100%;\n  padding: 10px;\n  border: none;\n  background: #3498db;\n  color: #fff;\n  font-weight: bold;\n  border-radius: 4px;\n  cursor: pointer;\n  box-shadow: 0px 3px 6px rgba(0, 0, 0, 0.1), inset 0px 1px 3px rgba(255, 255, 255, 0.5);\n  transition: background 0.3s ease, transform 0.2s ease;\n}\n\n.login-button:hover {\n  background: #2980b9;\n  transform: translateY(-2px);\n}"
