    "css": "/* From Uiverse.io by PriyanshuGupta28 - Tags: form, subscriptions card, email card */\n/* Unique styles for the newsletter form */\n.newsletter-form {\n  max-width: 400px;\n  margin: 0 auto;\n  padding: 20px;\n  border: 2px solid #333;\n  border-radius: 8px;\n  background-color: #f7f7f7;\n  font-family: Arial, sans-serif;\n  box-shadow: rgba(0, 0, 0, 0.3) 0px 19px 38px, rgba(0, 0, 0, 0.22) 0px 15px 12px;\n}\n\n.heading {\n  font-weight: bold;\n  font-size: 20px;\n}\n\n.newsletter-form h2 {\n  margin-top: 0;\n  color: #333;\n  font-size: 24px;\n}\n\n.newsletter-form label {\n  display: block;\n  font-weight: bold;\n  color: #666;\n  margin-bottom: 10px;\n}\n\n.newsletter-form input[type=\"email\"] {\n  width: 100%;\n  padding: 10px;\n  margin-bottom: 10px;\n  border: 1px solid #ccc;\n  border-radius: 4px;\n}\n\n.newsletter-form input[type=\"submit\"] {\n  width: 100%;\n  padding: 10px;\n  border: none;\n  border-radius: 4px;\n  background-color: #ff6600;\n  color: #fff;\n  font-weight: bold;\n  cursor: pointer;\n}\n\n.newsletter-form input[type=\"submit\"]:hover {\n  background-color: #ff8533;\n}"
