    "css": "/* From Uiverse.io by SteeveeG  - Website: https://www.jetbrains.com/de-de/ - Name: Jetbrains - Tags: login, sign-up, login form, rounded, simple, blue, password, email, white, signin, create, username, signup, clear, Google, GitHub, GitLab, Bitbucket, JetBrains, hyperlink, existing */\n.font {\n  font-family:\n    JetBrains Sans,\n    Inter,\n    system-ui,\n    -apple-system,\n    BlinkMacSystemFont,\n    Segoe UI,\n    Roboto,\n    Oxygen,\n    Ubuntu,\n    Cantarell,\n    Droid Sans,\n    Helvetica Neue,\n    Arial,\n    sans-serif;\n}\nform {\n  padding: 1.5em 1em;\n}\n.SignInForms {\n  background-color: rgb(245, 245, 245);\n  width: 22.375em;\n  height: 20.313em;\n}\n.header {\n  color: rgb(75, 75, 75);\n  font-size: 0.938em;\n  font-weight: 640;\n  margin: 0 0 0.875em 0;\n  display: block;\n}\n\n.Buttons {\n  padding: 0 0 1em;\n  border-bottom: solid #d2d0d0 0.063em;\n  margin-bottom: 1.188em;\n}\n\n.SignInUp {\n  cursor: pointer;\n  color: #ffffff;\n  background-color: #00a6fd;\n  border: none;\n  width: 6.875em;\n  padding: 0.5em 1.25em;\n  font-size: 0.875em;\n  line-height: 1.65;\n  border-radius: 1.25em;\n  touch-action: manipulation;\n  margin: 0 0.625em 0 0;\n}\n\n.ForgotPassword {\n  cursor: pointer;\n  color: #4c9dd0;\n  padding: 0.5em 0;\n  border: none;\n  text-decoration: none;\n  background-color: transparent;\n  font-size: 0.875em;\n}\n.ForgotPassword:hover {\n  text-decoration: underline;\n  background-color: transparent;\n}\n.Input {\n  padding: 0.25em;\n  vertical-align: middle;\n  width: 100%;\n  margin: 0 0 1em 0;\n  color: #4b4b4b;\n  height: 2.5em;\n  border: 1px solid #d9d9d9;\n}\n.Input:focus {\n  outline: none;\n  border-color: #00a6fd;\n}\n\n.SignInForms:focus-within,\n.NoAcc:focus-within {\n  -webkit-box-shadow: 0 0 6px 3px #caedff;\n  box-shadow: 0 0 6px 3px #caedff;\n  outline: 1px solid #97dbff;\n}\n\n.SignInUp:hover {\n  background-color: #008bd4;\n  border: #00a6fd;\n}\n\n.OtherSignInLabel {\n  margin-bottom: 0.688em;\n}\n\n.SignInWith {\n  display: flex;\n  align-items: center;\n}\n\n.GoogleLogo {\n  height: 1.25em;\n  width: 1.25em;\n  margin: 0 0.875em;\n}\n\n.SignInWithGoogle {\n  min-width: 8.5em;\n  height: 3em;\n  text-decoration: none;\n  color: #4b4b4b;\n  display: flex;\n  margin-right: 1.75em;\n  align-items: center;\n  position: relative;\n  box-shadow:\n    0 0 0.063em rgb(0 0 0 / 10%),\n    0 0.063em 0.063em #b7b7b7;\n  background: #ffffff;\n  border-radius: 0.125em;\n  user-select: none;\n  font-size: 0.813em;\n}\n\n.SignInWithLogo {\n  display: block;\n  margin-right: 1.75em;\n  position: relative;\n}\n\n.SignInWithLogo:hover .Bar {\n  transition: ease-in-out 0.5s;\n  opacity: 1;\n}\n.h3 {\n  display: block;\n  font-size: 1.17em;\n  font-weight: 600;\n  margin-bottom: 1em;\n}\n.Bar {\n  background-color: #b7b6b6;\n  bottom: -0.238em;\n  left: -0.25em;\n  position: relative;\n  height: 0.094em;\n  transition: ease-in-out 0.5s;\n  opacity: 0;\n  width: 2em;\n  border-radius: 6.25em;\n}\n\n.NoAcc {\n  top: 1em;\n  width: 22.375em;\n  height: 12.7em;\n  padding: 1.188em;\n  background-color: rgb(245, 245, 245);\n  position: relative;\n}\n.NoAccForms {\n  padding: 0;\n}\n.container {\n  display: flex;\n\n  flex-direction: column;\n}"
