    "animationLevel": "high",
    "html": "<form class=\"colorful-form\">\n  <div class=\"form-group\">\n    <label class=\"form-label\" for=\"name\">Name:</label>\n    <input required=\"\" placeholder=\"Enter your name\" class=\"form-input\" type=\"text\">\n  </div>\n  <div class=\"form-group\">\n    <label class=\"form-label\" for=\"email\">Email:</label>\n    <input required=\"\" placeholder=\"Enter your email\" class=\"form-input\" name=\"email\" id=\"email\" type=\"email\">\n  </div>\n  <div class=\"form-group\">\n    <label class=\"form-label\" for=\"message\">Message:</label>\n    <textarea required=\"\" placeholder=\"Enter your message\" class=\"form-input\" name=\"message\" id=\"message\"></textarea>\n  </div>\n  <button class=\"form-button\" type=\"submit\">Submit</button>\n</form>",
    "css": "/* From Uiverse.io by StefanR1901 - Tags: form, input, discount form */\n.colorful-form {\n  max-width: 400px;\n  margin: 0 auto;\n  padding: 20px;\n  background-color: #f5f5f5;\n  border-radius: 10px;\n}\n\n.form-group {\n  margin-bottom: 20px;\n}\n\n.form-label {\n  display: block;\n  font-weight: bold;\n  margin-bottom: 5px;\n  color: #333;\n}\n\n.form-input {\n  width: 100%;\n  padding: 10px;\n  border: none;\n  background-color: #fff;\n  color: #333;\n  border-radius: 5px;\n}\n\ntextarea.form-input {\n  height: 100px;\n}\n\n.form-button {\n  display: block;\n  width: 100%;\n  padding: 10px;\n  background-color: #ff6f69;\n  color: #fff;\n  border: none;\n  border-radius: 5px;\n  cursor: pointer;\n  transition: background-color 0.3s ease;\n}\n\n.form-button:hover {\n  background-color: #ff5f59;\n}"
