    "html": "<form class=\"form-control\" action=\"\">\n  <p class=\"title\">Login</p>\n  <div class=\"input-field\">\n    <input required=\"\" class=\"input\" type=\"text\" />\n    <label class=\"label\" for=\"input\">Enter Email</label>\n  </div>\n  <div class=\"input-field\">\n    <input required=\"\" class=\"input\" type=\"password\" />\n    <label class=\"label\" for=\"input\">Enter Password</label>\n  </div>\n  <a>Forgot your password?</a>\n  <button class=\"submit-btn\">Sign In</button>\n</form>",
    "css": "/* From Uiverse.io by VitorBaraoDias  - Tags: simple, animation, form, creative, login , login form, click effect, input effect  */\n.form-control {\n  margin: 20px;\n  background-color: #ffffff;\n  box-shadow: 0 15px 25px rgba(0, 0, 0, 0.6);\n  width: 400px;\n  display: flex;\n  justify-content: center;\n  flex-direction: column;\n  gap: 10px;\n  padding: 25px;\n  border-radius: 8px;\n}\n.title {\n  font-size: 28px;\n  font-weight: 800;\n}\n.input-field {\n  position: relative;\n  width: 100%;\n}\n\n.input {\n  margin-top: 15px;\n  width: 100%;\n  outline: none;\n  border-radius: 8px;\n  height: 45px;\n  border: 1.5px solid #ecedec;\n  background: transparent;\n  padding-left: 10px;\n}\n.input:focus {\n  border: 1.5px solid #2d79f3;\n}\n.input-field .label {\n  position: absolute;\n  top: 25px;\n  left: 15px;\n  color: #ccc;\n  transition: all 0.3s ease;\n  pointer-events: none;\n  z-index: 2;\n}\n.input-field .input:focus ~ .label,\n.input-field .input:valid ~ .label {\n  top: 5px;\n  left: 5px;\n  font-size: 12px;\n  color: #2d79f3;\n  background-color: #ffffff;\n  padding-left: 5px;\n  padding-right: 5px;\n}\n.submit-btn {\n  margin-top: 30px;\n  height: 55px;\n  background: #f2f2f2;\n  border-radius: 11px;\n  border: 0;\n  outline: none;\n  color: #ffffff;\n  font-size: 18px;\n  font-weight: 700;\n  background: linear-gradient(180deg, #363636 0%, #1b1b1b 50%, #000000 100%);\n  box-shadow: 0px 0px 0px 0px #ffffff, 0px 0px 0px 0px #000000;\n  transition: all 0.3s cubic-bezier(0.15, 0.83, 0.66, 1);\n  cursor: pointer;\n}\n\n.submit-btn:hover {\n  box-shadow: 0px 0px 0px 2px #ffffff, 0px 0px 0px 4px #0000003a;\n}"
