    "css": "/* From Uiverse.io by Yaya12085 - Tags: form */\n.modal {\n  background-color: rgb(255, 255, 255);\n  border-radius: 1em;\n  box-shadow: 0px 100px 48px -60px rgba(0,0,0,0.1);\n  color: rgb(15, 14, 14);\n  max-width: 330px;\n  overflow: hidden;\n  position: relative;\n  transition: background-color 0.3s, color 0.3s;\n}\n\n.content > *, .modal > * {\n  padding: 0.875em;\n}\n\n.title {\n  font-size: 1.25em;\n  font-weight: 600;\n  line-height: 1.2;\n  display: flex;\n  justify-content: center;\n}\n\n.message {\n  line-height: 1.2;\n  text-align: center;\n}\n\n.actions {\n  display: flex;\n  align-items: center;\n  flex-wrap: wrap;\n}\n\n.upload-btn {\n  background-color: transparent;\n  border: 0.125rem dashed hsla(223,10%,50%,0.4);\n  flex: 1;\n  padding: 0.375rem 2rem;\n}\n\n.upload-btn:hover {\n  background-color: hsla(223,10%,60%,0.2);\n}\n\n.close {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  background-color: rgb(226, 94, 54);\n  height: 30px;\n  width: 30px;\n  border-radius: 50%;\n  position: absolute;\n  right: 10px;\n  top: 10px;\n  color: #fff;\n  font-weight: bold;\n  cursor: pointer;\n}\n\n.result {\n  margin-top: 4px;\n  background-color: rgba(0, 140, 255, 0.062);\n  display: flex;\n  align-items: center;\n  position: relative;\n  border-radius: 1em;\n}\n\n.file-uploaded {\n  font-weight: 300;\n}\n\n.file-uploaded::before {\n  position: absolute;\n  content: \"X\";\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  background-color: rgba(26, 7, 1, 0.212);\n  height: 30px;\n  width: 30px;\n  border-radius: 50%;\n  right: 10px;\n  top: 10px;\n  color: rgb(255, 255, 255);\n  font-weight: bold;\n  cursor: pointer;\n}\n\n.file-uploaded:hover::before {\n  background-color: rgba(233, 40, 6, 0.664);\n}"
