    "css": "/* From Uiverse.io by Yaya12085 - Tags: OTP, form */\n.form {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  position: relative;\n  overflow: hidden;\n  padding: 20px;\n  background: #606c88;\n  background: -webkit-linear-gradient(to right, #3f4c6b, #606c88);\n  background: linear-gradient(to right, #3f4c6b, #606c88);\n  border-radius: 10px;\n  box-shadow: 0px 87px 78px -39px rgba(0,0,0,0.4);\n  max-width: 320px;\n}\n\n.info {\n  margin-bottom: 10px;\n}\n\n.title {\n  color: #fff;\n  font-size: 1.5rem;\n  line-height: 1.8rem;\n  font-weight: 800;\n  letter-spacing: -0.025em;\n}\n\n.description {\n  color: #fff;\n  margin-top: 10px;\n  font-size: 15px;\n}\n\n.form .inputs {\n  display: flex;\n  justify-content: space-between;\n  gap: 10px;\n}\n\n.form .inputs input {\n  height: 2.5em;\n  width: 2.5em;\n  outline: none;\n  text-align: center;\n  font-size: 1.5em;\n  color: #fff;\n  border-radius: 0.3em;\n  border: 1px solid rgba(253, 253, 253, 0.363);\n  background-color: rgb(255 255 255 / 0.05);\n}\n\n.form .inputs input:focus {\n  border: 1px solid rgb(99 102 241);\n}\n\n.resend {\n  color: #fff;\n  margin-top: 10px;\n  font-size: 15px;\n  text-align: center;\n}\n\n.resend-action {\n  text-decoration: none;\n  cursor: pointer;\n  margin-left: 6px;\n  color: rgb(255, 255, 255);\n  font-weight: 600;\n}\n\n.resend-action:hover {\n  text-decoration: underline #2b8af7;\n}\n\n.validate {\n  display: flex;\n  align-items: flex-end;\n  justify-content: flex-end;\n  text-decoration: none;\n  background-color: #606c88;\n  padding: 10px 20px;\n  margin: 8px 0 0 0;\n  font-size: 13px;\n  font-weight: 600;\n  border-radius: 10px;\n  transition: .3s ease;\n}\n\n.validate:hover {\n  background-color: #3f4c6b;\n}\n\n.close {\n  position: absolute;\n  right: 10px;\n  top: 10px;\n  background-color: #3f4c6b;\n  height: 30px;\n  width: 30px;\n  display: grid;\n  place-items: center;\n  border-radius: 50%;\n  cursor: pointer;\n  font-weight: 600;\n  transition: .3s ease;\n}\n\n.close:hover {\n  background-color: rgba(255, 0, 0, 0.603);\n}"
