    "css": "/* From Uiverse.io by Yaya12085 - Tags: sign-in, form */\n.form {\n  background-color: #fff;\n  display: block;\n  padding: 1rem;\n  max-width: 350px;\n  border-radius: 0.5rem;\n  box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1), 0 4px 6px -2px rgba(0, 0, 0, 0.05);\n}\n\n.form-title {\n  font-size: 1.25rem;\n  line-height: 1.75rem;\n  font-weight: 600;\n  text-align: center;\n  color: #000;\n}\n\n.input-container {\n  position: relative;\n}\n\n.input-container input, .form button {\n  outline: none;\n  border: 1px solid #e5e7eb;\n  margin: 8px 0;\n}\n\n.input-container input {\n  background-color: #fff;\n  padding: 1rem;\n  padding-right: 3rem;\n  font-size: 0.875rem;\n  line-height: 1.25rem;\n  width: 300px;\n  border-radius: 0.5rem;\n  box-shadow: 0 1px 2px 0 rgba(0, 0, 0, 0.05);\n}\n\n.input-container span {\n  display: grid;\n  position: absolute;\n  top: 0;\n  bottom: 0;\n  right: 0;\n  padding-left: 1rem;\n  padding-right: 1rem;\n  place-content: center;\n}\n\n.input-container span svg {\n  color: #9CA3AF;\n  width: 1rem;\n  height: 1rem;\n}\n\n.submit {\n  display: block;\n  padding-top: 0.75rem;\n  padding-bottom: 0.75rem;\n  padding-left: 1.25rem;\n  padding-right: 1.25rem;\n  background-color: #4F46E5;\n  color: #ffffff;\n  font-size: 0.875rem;\n  line-height: 1.25rem;\n  font-weight: 500;\n  width: 100%;\n  border-radius: 0.5rem;\n  text-transform: uppercase;\n}\n\n.signup-link {\n  color: #6B7280;\n  font-size: 0.875rem;\n  line-height: 1.25rem;\n  text-align: center;\n}\n\n.signup-link a {\n  text-decoration: underline;\n}"
