" placeholder=\"email\">\n    <input type=\"password\" class=\"input\" placeholder=\"password\"> \n  <span class=\"sub\">Already have an account ? <a href=\"#\">Sign in</a></span>\n    <button>Register</button>\n</form>",
    "css": "/* From Uiverse.io by Yaya12085 - Tags: form */\n.form {\n  display: flex;\n  flex-direction: column;\n  gap: 10px;\n  width: 300px;\n  background-color: #fff;\n  border-radius: 20px;\n  padding: 30px 20px;\n  box-shadow: 100px 100px 80px rgba(0, 0, 0, 0.03)\n}\n\n.title {\n  color: black;\n  font-weight: bold;\n  text-align: center;\n  font-size: 20px;\n  margin-bottom: 4px;\n}\n\n.sub {\n  text-align: center;\n  color: black;\n  font-size: 14px;\n  width: 100%;\n}\n\n.sub.mb {\n  margin-bottom: 1px;\n}\n\n.sub a {\n  color: rgb(23, 111, 211);\n}\n\n.avatar {\n  height: 50px;\n  width: 50px;\n  background-color: rgb(23, 111, 211);\n  border-radius: 50%;\n  align-self: center;\n  padding: 6px;\n  cursor: pointer;\n  box-shadow: 12.5px 12.5px 10px rgba(0, 0, 0, 0.015),100px 100px 80px rgba(0, 0, 0, 0.03);\n}\n\n.form button {\n  align-self: flex-end;\n}\n\n.input, button {\n  border: none;\n  outline: none;\n  width: 100%;\n  padding: 16px 10px;\n  background-color: rgb(247, 243, 243);\n  border-radius: 10px;\n  box-shadow: 12.5px 12.5px 10px rgba(0, 0, 0, 0.015),100px 100px 80px rgba(0, 0, 0, 0.03);\n}\n\nbutton {\n  margin-top: 12px;\n  background-color: rgb(23, 111, 211);\n  color: #fff;\n  text-transform: uppercase;\n  font-weight: bold;\n}\n\n.input:focus {\n  border: 1px solid rgb(23, 111, 211);\n}\n\n#file {\n  display: none;\n}"
