    "css": "/* From Uiverse.io by aadium - Tags: form, chat */\n.form {\n  display: flex;\n  align-items: center;\n  flex-direction: column;\n  gap: 10px;\n  background-image: linear-gradient(45deg, #330808, \n  #3a2c09);\n  border-radius: 2.5em;\n  padding: 30px;\n  width: 300px;\n  height: 350px;\n}\n\n.form::before {\n  content: '';\n  background-image: linear-gradient(45deg, #ff0000, \n  #ffb700);\n  height: 358px;\n  width: 309px;\n  position: absolute;\n  margin-top: -34px;\n  margin-left: px;\n  z-index: -1;\n  border-radius: 2.7em;\n}\n\n.button {\n  margin-top: 10px;\n  font-family: Arial, Helvetica, sans-serif;\n  font-size: 17px;\n  background: #ff5900;\n  color: black;\n  padding: 0.7em 5.5em;\n  display: flex;\n  align-items: center;\n  border: 2px solid #66da4300;\n  border-radius: 5em;\n  overflow: hidden;\n  transition: all 0.2s;\n  cursor: pointer;\n}\n\n.button:hover {\n  border: 2px solid #ff5900;\n  background: #00000000;\n  color: #ff5900;\n}\n\n.button:active {\n  border: 2px solid #66da4300;\n  background: #ff5900;\n  color: black;\n}\n\n.input {\n  width: calc(100% - 10px);\n  padding: 8px;\n  margin-bottom: 20px;\n  border: 1px solid #66da4300;\n  border-bottom: 1px solid #ff5900;\n  outline: none;\n  background-color: transparent;\n  color: #ff5900;\n  font-family: Arial, Helvetica, sans-serif;\n  transition: 0.2s;\n}\n\n.input:focus {\n  border: 1px solid #66da4300;\n  border-bottom: 1px solid #ff5900;\n  background-color: transparent;\n  color: white;\n}\n\n.input::placeholder {\n  color: #9b725b;\n}\n\n.textarea {\n  font-family: Arial, Helvetica, sans-serif;\n  width: calc(100% - 10px);\n  padding: 8px;\n  height: 100px;\n  margin-bottom: 20px;\n  border: 1px solid #66da4300;\n  border-bottom: 1px solid #ff5900;\n  outline: none;\n  background-color: transparent;\n  color: #ff5900;\n}\n\n.textarea::placeholder {\n  color: #9b725b;\n}\n\n.textarea:focus {\n  border: 1px solid #66da4300;\n  border-bottom: 1px solid #ff5900;\n  background-color: transparent;\n  color: white;\n}"
