    "css": "/* From Uiverse.io by ahmed150up - Tags: pause, play, music, soundCloud */\n.audio-player {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  width: 300px;\n  height: 80px;\n  background-color: #f3f3f3;\n  border-radius: 8px;\n  padding: 8px;\n  box-sizing: border-box;\n}\n\n.player-controls {\n  flex-grow: 1;\n  display: flex;\n  flex-direction: column;\n}\n\n.song-info {\n  margin-bottom: 4px;\n}\n\n.song-title {\n  font-size: 16px;\n  color: #333;\n  margin: 0;\n}\n\n.artist {\n  font-size: 12px;\n  color: #666;\n  margin: 0;\n}\n\n.progress-bar {\n  width: 100%;\n  height: 4px;\n  background-color: #ddd;\n  border-radius: 2px;\n  overflow: hidden;\n}\n\n.progress {\n  width: 0;\n  height: 100%;\n  background-color: #ff5500;\n  animation: progress-animation 10s linear infinite;\n}\n\n.buttons {\n  display: flex;\n  align-items: center;\n  margin-top: 4px;\n}\n\nbutton {\n  background: none;\n  border: none;\n  cursor: pointer;\n  outline: none;\n}\n\n.play-btn,\n.pause-btn,\n.skip-btn,\n.volume-btn {\n  font-size: 16px;\n  color: #666;\n  margin-right: 8px;\n  transition: transform 0.2s ease-in-out;\n}\n\n.play-btn:hover,\n.pause-btn:hover,\n.skip-btn:hover,\n.volume-btn:hover {\n  transform: scale(1.2);\n}\n\n.volume-slider {\n  width: 100px;\n  height: 5px;\n  background-color: #ccc;\n  position: relative;\n  margin-left: 10px;\n}\n\n.volume-slider-bar {\n  height: 100%;\n  background-color: #666;\n}\n\n.volume-slider-handle {\n  width: 16px;\n  height: 16px;\n  background-color: #666;\n  position: absolute;\n  top: 50%;\n  transform: translate(-50%, -50%);\n  border-radius: 50%;\n  cursor: pointer;\n}\n\n@keyframes progress-animation {\n  0% {\n    width: 0;\n  }\n\n  100% {\n    width: 100%;\n  }\n}"
