    "html": "<!-- From Uiverse.io by alexruix  - Tags: simple, email, purple, minimalist, form, tailwind, tailwindcss -->\n<div class=\"mx-auto max-w-screen-xl px-4 py-16 sm:px-6 lg:px-8\">\n  <div class=\"mx-auto max-w-lg text-center\">\n    <h1 class=\"text-2xl font-bold sm:text-3xl\">Welcome Back!</h1>\n    <p class=\"mt-4 text-gray-600\">\n      Lorem ipsum dolor sit amet consectetur adipisicing elit. Et libero nulla\n      eaque error neque ipsa culpa autem, at itaque nostrum!\n    </p>\n  </div>\n\n  <form class=\"mx-auto mb-0 mt-8 max-w-md space-y-4\" action=\"#\">\n    <div>\n      <label class=\"sr-only\" for=\"email\">Email</label>\n      <div class=\"relative\">\n        <input\n          placeholder=\"Enter your email\"\n          class=\"w-full rounded-lg border-gray-300 p-4 pe-12 text-sm shadow-sm focus:outline-none focus:ring-2 focus:ring-purple-400 focus:border-transparent\"\n          id=\"email\"\n          type=\"email\"\n        />\n        <span class=\"absolute inset-y-0 end-0 grid place-content-center px-4\">\n          <svg\n            stroke=\"currentColor\"\n            viewBox=\"0 0 24 24\"\n            fill=\"none\"\n            class=\"h-6 w-6 text-gray-400\"\n            xmlns=\"http://www.w3.org/2000/svg\"\n          >\n            <path\n              d=\"M16 12a4 4 0 10-8 0 4 4 0 008 0zm0 0v1.5a2.5 2.5 0 005 0V12a9 9 0 10-9 9m4.5-1.206a8.959 8.959 0 01-4.5 1.207\"\n              stroke-width=\"2\"\n              stroke-linejoin=\"round\"\n              stroke-linecap=\"round\"\n            ></path>\n          </svg>\n        </span>\n      </div>\n    </div>\n\n    <div>\n      <label class=\"sr-only\" for=\"password\">Password</label>\n      <div class=\"relative\">\n        <input\n          placeholder=\"Enter your password\"\n          class=\"w-full rounded-lg border-gray-300 p-4 pe-12 text-sm shadow-sm focus:outline-none focus:ring-2 focus:ring-purple-400 focus:border-transparent\"\n          id=\"password\"\n          type=\"password\"\n        />\n        <span class=\"absolute inset-y-0 end-0 grid place-content-center px-4\">\n          <svg\n            stroke=\"currentColor\"\n            viewBox=\"0 0 24 24\"\n            fill=\"none\"\n            class=\"h-6 w-6 text-gray-400\"\n            xmlns=\"http://www.w3.org/2000/svg\"\n          >\n            <path\n              d=\"M15 12a3 3 0 11-6 0 3 3 0 016 0z\"\n              stroke-width=\"2\"\n              stroke-linejoin=\"round\"\n              stroke-linecap=\"round\"\n            ></path>\n            <path\n              d=\"M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z\"\n              stroke-width=\"2\"\n              stroke-linejoin=\"round\"\n              stroke-linecap=\"round\"\n            ></path>\n          </svg>\n        </span>\n      </div>\n    </div>\n\n    <div class=\"flex items-center justify-between\">\n      <p class=\"text-sm text-gray-600\">\n        No account yet?\n        <a href=\"#\" class=\"underline\">Create one</a>\n      </p>\n      <button\n        class=\"inline-block rounded-lg bg-purple-600 px-5 py-3 text-sm font-medium text-white focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-opacity-50\"\n        type=\"submit\"\n      >\n        Sign In\n      </button>\n    </div>\n  </form>\n</div>",
    "css": ""
