    "css": "/* From Uiverse.io by boryanakrasteva - Tags: form */\n.form {\n  width: 250px;\n  display: flex;\n  flex-direction: column;\n  gap: 20px;\n  border-radius: 10px;\n  padding: 20px 40px;\n  background-color: rgba(245, 245, 245, 0.034);\n  box-shadow: 2px 2px 10px rgba(0, 0, 0, 0.192);\n  transition: .2s linear;\n}\n\n.form button {\n  align-self: flex-end;\n}\n\n.form:hover {\n  transform: scale(1.1);\n}\n\n.label {\n  font-size: 14px;\n  margin-bottom: -10.6px;\n}\n\n.input {\n  height: 25px;\n  width: 100%;\n  border: 0.5px solid white;\n  background-color: transparent;\n  color: white;\n  padding: 5px;\n  border-radius: 5px;\n  transition: .2s linear;\n  position: relative;\n}\n\n.input:focus {\n  outline: none;\n  background-color: rgba(173, 173, 173, 0.233);\n  box-shadow: 1px 1px 10px rgba(255, 255, 255, 0.137);\n}\n\nbutton {\n  border: none;\n  padding: 4px 10px;\n  border-radius: 5px;\n  transition: .2s linear;\n}\n\nbutton:hover {\n  background-color: rgba(255, 255, 255, 0.74);\n  box-shadow: 2px 2px 10px rgba(124, 124, 124, 0.192);\n}"
