    "css": "/* From Uiverse.io by csozidev - Tags: simple, white, form, light, microsoft, clean, login , login form, log in, simple form */\n/* Microsoft log in page made by: csozi | Website: english.csozi.hu*/\n\n.form {\n/*Scale only to make it look right on the preview*/\n  scale: 0.8;\n  background-color: #ffffff;\n  height: 250px;\n  width: 352px;\n  box-sizing: content-box;\n  padding: 44px;\n}\n\n.form .title {\n  color: #1b1b1b;\n  font-size: 1.5rem;\n  font-weight: 600;\n  padding: 0;\n  margin-top: 16px;\n  margin-bottom: 12px;\n  font-family: \"Segoe UI\",\"Helvetica Neue\",\"Lucida Grande\",\"Roboto\",\"Ebrima\",\"Nirmala UI\",\"Gadugi\",\"Segoe Xbox Symbol\",\"Segoe UI Symbol\",\"Meiryo UI\",\"Khmer UI\",\"Tunga\",\"Lao UI\",\"Raavi\",\"Iskoola Pota\",\"Latha\",\"Leelawadee\",\"Microsoft YaHei UI\",\"Microsoft JhengHei UI\",\"Malgun Gothic\",\"Estrangelo Edessa\",\"Microsoft Himalaya\",\"Microsoft New Tai Lue\",\"Microsoft PhagsPa\",\"Microsoft Tai Le\",\"Microsoft Yi Baiti\",\"Mongolian Baiti\",\"MV Boli\",\"Myanmar Text\",\"Cambria Math\";\n}\n\n.form .email {\n  width: 100%;\n  padding: 6px 10px 6px 0px;\n  border-style: solid;\n  border-width: 0px;\n  border-bottom-width: 1px;\n  border-color: rgba(0, 0, 0, 0.6);\n  height: 36px;\n  outline: none;\n  background-color: transparent;\n  padding-left: 0;\n  color: #000000;\n  margin-bottom: 16px;\n}\n\n.form .email {\n  border-color: rgba(0, 0, 0, 0.8);\n}\n\n.form .text {\n  color: #1b1b1b;\n  font-family: \"Segoe UI Webfont\",-apple-system,\"Helvetica Neue\",\"Lucida Grande\",\"Roboto\",\"Ebrima\",\"Nirmala UI\",\"Gadugi\",\"Segoe Xbox Symbol\",\"Segoe UI Symbol\",\"Meiryo UI\",\"Khmer UI\",\"Tunga\",\"Lao UI\",\"Raavi\",\"Iskoola Pota\",\"Latha\",\"Leelawadee\",\"Microsoft YaHei UI\",\"Microsoft JhengHei UI\",\"Malgun Gothic\",\"Estrangelo Edessa\",\"Microsoft Himalaya\",\"Microsoft New Tai Lue\",\"Microsoft PhagsPa\",\"Microsoft Tai Le\",\"Microsoft Yi Baiti\",\"Mongolian Baiti\",\"MV Boli\",\"Myanmar Text\",\"Cambria Math\";\n  font-weight: 400;\n  line-height: 1.25rem;\n  margin-bottom: 16px;\n  font-size: .8125rem;\n}\n\n.form .text a {\n  color: #0067B8;\n}\n\n.form .button_row {\n  width: 100%;\n  display: flex;\n  justify-content: end;\n  height: fit-content;\n  gap: 4px;\n}\n\n.form .button_row .button {\n  width: 108px;\n  height: 32px;\n  box-sizing: content-box;\n  padding: 4 12 4 12;\n  border: none;\n  font-size: 15px;\n}\n\n.form .button_row .secondary_button {\n  background-color: rgba(0,0,0,0.2);\n  text-align: center;\n  white-space: nowrap;\n  overflow: hidden;\n  vertical-align: middle;\n  text-overflow: ellipsis;\n  touch-action: manipulation;\n  color: #000;\n  cursor: pointer;\n}\n\n.form .button_row .secondary_button:hover {\n  background-color: rgba(0,0,0,0.3);\n}\n\n.form .button_row .primary_button {\n  background-color: #0067b8;\n  color: #ffffff;\n  cursor: pointer;\n}\n\n.form .button_row .primary_button:hover {\n  background-color: #005da6;\n}"
