    "css": "/* From Uiverse.io by gharsh11032000 - Tags: form, password, simple form, forgot password */\n.form-container {\n  max-width: 400px;\n  background-color: #fff;\n  padding: 32px 24px;\n  font-size: 14px;\n  font-family: inherit;\n  color: #212121;\n  display: flex;\n  flex-direction: column;\n  gap: 20px;\n  box-sizing: border-box;\n  border-radius: 10px;\n  box-shadow: 0px 0px 3px rgba(0, 0, 0, 0.084), 0px 2px 3px rgba(0, 0, 0, 0.168);\n}\n\n.form-container button:active {\n  scale: 0.95;\n}\n\n.form-container .logo-container {\n  text-align: center;\n  font-weight: 600;\n  font-size: 18px;\n}\n\n.form-container .form {\n  display: flex;\n  flex-direction: column;\n}\n\n.form-container .form-group {\n  display: flex;\n  flex-direction: column;\n  gap: 2px;\n}\n\n.form-container .form-group label {\n  display: block;\n  margin-bottom: 5px;\n}\n\n.form-container .form-group input {\n  width: 100%;\n  padding: 12px 16px;\n  border-radius: 6px;\n  font-family: inherit;\n  border: 1px solid #ccc;\n}\n\n.form-container .form-group input::placeholder {\n  opacity: 0.5;\n}\n\n.form-container .form-group input:focus {\n  outline: none;\n  border-color: #1778f2;\n}\n\n.form-container .form-submit-btn {\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  font-family: inherit;\n  color: #fff;\n  background-color: #212121;\n  border: none;\n  width: 100%;\n  padding: 12px 16px;\n  font-size: inherit;\n  gap: 8px;\n  margin: 12px 0;\n  cursor: pointer;\n  border-radius: 6px;\n  box-shadow: 0px 0px 3px rgba(0, 0, 0, 0.084), 0px 2px 3px rgba(0, 0, 0, 0.168);\n}\n\n.form-container .form-submit-btn:hover {\n  background-color: #313131;\n}\n\n.form-container .link {\n  color: #1778f2;\n  text-decoration: none;\n}\n\n.form-container .signup-link {\n  align-self: center;\n  font-weight: 500;\n}\n\n.form-container .signup-link .link {\n  font-weight: 400;\n}\n\n.form-container .link:hover {\n  text-decoration: underline;\n}"
