    "animationLevel": "high",
    "html": "<div class=\"login-box\">\n  <p>Login</p>\n  <form>\n    <div class=\"user-box\">\n      <input required=\"\" name=\"\" type=\"text\">\n      <label>Email</label>\n    </div>\n    <div class=\"user-box\">\n      <input required=\"\" name=\"\" type=\"password\">\n      <label>Password</label>\n    </div>\n    <a href=\"#\">\n      <span></span>\n      <span></span>\n      <span></span>\n      <span></span>\n      Submit\n    </a>\n  </form>\n  <p>Don't have an account? <a href=\"\" class=\"a2\">Sign up!</a></p>\n</div>",
    "css": "/* From Uiverse.io by glisovic01 - Tags: login, form */\n.login-box {\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  width: 400px;\n  padding: 40px;\n  margin: 20px auto;\n  transform: translate(-50%, -55%);\n  background: rgba(0,0,0,.9);\n  box-sizing: border-box;\n  box-shadow: 0 15px 25px rgba(0,0,0,.6);\n  border-radius: 10px;\n}\n\n.login-box p:first-child {\n  margin: 0 0 30px;\n  padding: 0;\n  color: #fff;\n  text-align: center;\n  font-size: 1.5rem;\n  font-weight: bold;\n  letter-spacing: 1px;\n}\n\n.login-box .user-box {\n  position: relative;\n}\n\n.login-box .user-box input {\n  width: 100%;\n  padding: 10px 0;\n  font-size: 16px;\n  color: #fff;\n  margin-bottom: 30px;\n  border: none;\n  border-bottom: 1px solid #fff;\n  outline: none;\n  background: transparent;\n}\n\n.login-box .user-box label {\n  position: absolute;\n  top: 0;\n  left: 0;\n  padding: 10px 0;\n  font-size: 16px;\n  color: #fff;\n  pointer-events: none;\n  transition: .5s;\n}\n\n.login-box .user-box input:focus ~ label,\n.login-box .user-box input:valid ~ label {\n  top: -20px;\n  left: 0;\n  color: #fff;\n  font-size: 12px;\n}\n\n.login-box form a {\n  position: relative;\n  display: inline-block;\n  padding: 10px 20px;\n  font-weight: bold;\n  color: #fff;\n  font-size: 16px;\n  text-decoration: none;\n  text-transform: uppercase;\n  overflow: hidden;\n  transition: .5s;\n  margin-top: 40px;\n  letter-spacing: 3px\n}\n\n.login-box a:hover {\n  background: #fff;\n  color: #272727;\n  border-radius: 5px;\n}\n\n.login-box a span {\n  position: absolute;\n  display: block;\n}\n\n.login-box a span:nth-child(1) {\n  top: 0;\n  left: -100%;\n  width: 100%;\n  height: 2px;\n  background: linear-gradient(90deg, transparent, #fff);\n  animation: btn-anim1 1.5s linear infinite;\n}\n\n@keyframes btn-anim1 {\n  0% {\n    left: -100%;\n  }\n\n  50%,100% {\n    left: 100%;\n  }\n}\n\n.login-box a span:nth-child(2) {\n  top: -100%;\n  right: 0;\n  width: 2px;\n  height: 100%;\n  background: linear-gradient(180deg, transparent, #fff);\n  animation: btn-anim2 1.5s linear infinite;\n  animation-delay: .375s\n}\n\n@keyframes btn-anim2 {\n  0% {\n    top: -100%;\n  }\n\n  50%,100% {\n    top: 100%;\n  }\n}\n\n.login-box a span:nth-child(3) {\n  bottom: 0;\n  right: -100%;\n  width: 100%;\n  height: 2px;\n  background: linear-gradient(270deg, transparent, #fff);\n  animation: btn-anim3 1.5s linear infinite;\n  animation-delay: .75s\n}\n\n@keyframes btn-anim3 {\n  0% {\n    right: -100%;\n  }\n\n  50%,100% {\n    right: 100%;\n  }\n}\n\n.login-box a span:nth-child(4) {\n  bottom: -100%;\n  left: 0;\n  width: 2px;\n  height: 100%;\n  background: linear-gradient(360deg, transparent, #fff);\n  animation: btn-anim4 1.5s linear infinite;\n  animation-delay: 1.125s\n}\n\n@keyframes btn-anim4 {\n  0% {\n    bottom: -100%;\n  }\n\n  50%,100% {\n    bottom: 100%;\n  }\n}\n\n.login-box p:last-child {\n  color: #aaa;\n  font-size: 14px;\n}\n\n.login-box a.a2 {\n  color: #fff;\n  text-decoration: none;\n}\n\n.login-box a.a2:hover {\n  background: transparent;\n  color: #aaa;\n  border-radius: 5px;\n}"
