    "animationLevel": "high",
    "html": "<form class=\"form\">\n    <input placeholder=\"Email address or phone number\" class=\"input\" type=\"text\">\n    <input placeholder=\"Password\" class=\"input\" type=\"password\" id=\"password\"> \n    <button id=\"loginBtn\">Log in</button>\n    <a id=\"forgotPassword\" href=\"#\">Forgotten password?</a>\n    <button class=\"create\" id=\"createAccountBtn\">Create new account</button>\n</form>",
    "css": "/* From Uiverse.io by iamriishav - Tags: form */\n.form {\n  width: 300px;\n  background-color: rgba(255, 255, 255, 1);\n  display: flex;\n  flex-direction: column;\n  gap: 10px;\n  padding: 10px 20px;\n  box-shadow: 0 0 5px rgba(0, 0, 0, .2);\n  border-radius: 5px;\n  font-family: inherit;\n}\n\n.input {\n  font-size: 15px;\n  padding: 15px 10px;\n  border-radius: 5px;\n  border: none;\n  margin-top: 10px;\n  box-shadow: inset 0 1px 1px rgba(0, 0, 0, .2), 0 .5px .5px rgba(0, 0, 0, .2);\n  outline: none;\n}\n\n.input:focus {\n  outline: 1.2px solid #1877f2;\n}\n\n#loginBtn {\n  margin-top: 10px;\n  width: 100%;\n  padding: 10px 20px;\n  align-self: center;\n  background: #1877f2;\n  border: none;\n  border-radius: 5px;\n  color: #fff;\n  font-size: 1.3rem;\n  font-weight: bold;\n}\n\n#loginBtn:hover {\n  background: #196fe0;\n}\n\n#forgotPassword {\n  text-align: center;\n  position: relative;\n  margin-top: 10px;\n  width: 100%;\n  font-size: 13px;\n  align-self: center;\n  font-weight: bold;\n  color: #1877f2;\n}\n\n#forgotPassword::after {\n  position: absolute;\n  content: '';\n  width: 100%;\n  height: .5px;\n  bottom: -25px;\n  left: 0;\n  background: #dadde1;\n}\n\n#forgotPassword:hover {\n  text-decoration: underline;\n}\n\n#createAccountBtn {\n  margin-top: 40px;\n  margin-bottom: 10px;\n  padding: 15px 15px;\n  align-self: center;\n  background: #42b72a;\n  border: none;\n  border-radius: 5px;\n  color: #fff;\n  font-size: 1rem;\n  font-weight: bold;\n}\n\n#createAccountBtn:hover {\n  background: #34a61d;\n}"
