    "css": "/* From Uiverse.io by kennyotsu - Tags: login, OTP, confirmation, form, phone */\n.design-container {\n  position: relative;\n  font-family: Arial, Helvetica, sans-serif;\n}\n\n.design-wrapper {\n  position: absolute;\n  display: -webkit-box;\n  display: -ms-flexbox;\n  display: flex;\n  -webkit-box-orient: vertical;\n  -webkit-box-direction: normal;\n  -ms-flex-direction: column;\n  flex-direction: column;\n  -webkit-box-align: center;\n  -ms-flex-align: center;\n  align-items: center;\n  -webkit-box-pack: center;\n  -ms-flex-pack: center;\n  justify-content: center;\n  gap: 0.8rem;\n  height: 100%;\n  width: 100%;\n}\n\n.call {\n  width: 280px;\n  height: 90px;\n  border-radius: 1.2rem;\n  background: rgba(19, 19, 19, 0.836);\n  overflow: hidden;\n  display: -webkit-box;\n  display: -ms-flexbox;\n  display: flex;\n  -webkit-box-orient: horizontal;\n  -webkit-box-direction: normal;\n  -ms-flex-direction: row;\n  flex-direction: row;\n  -webkit-box-pack: justify;\n  -ms-flex-pack: justify;\n  justify-content: space-between;\n  -webkit-box-align: center;\n  -ms-flex-align: center;\n  align-items: center;\n  -webkit-backdrop-filter: blur(15px);\n  backdrop-filter: blur(15px);\n  padding: 1rem;\n  color: #fff;\n  font-size: large;\n  font-weight: bold;\n  -webkit-box-shadow: 0px 0.2rem 0.5rem rgba(20, 20, 20, 0.322);\n  box-shadow: 0px 0.2rem 0.5rem rgba(20, 20, 20, 0.322);\n  -webkit-perspective: 800px;\n  perspective: 800px;\n  -webkit-animation: scale-out 10s infinite;\n  animation: scale-out 10s infinite;\n  position: relative;\n}\n\n.call::before {\n  content: '';\n  background-color: #111111e3;\n  -webkit-filter: blur(5px);\n  filter: blur(5px);\n  inset: 0;\n  position: absolute;\n  z-index: -1;\n  text-align: center;\n}\n\n.phone-number::after {\n  content: \"1234\";\n  background: -webkit-gradient(linear, left top, right top, color-stop(20%, rgb(206, 206, 206)), color-stop(40%, rgb(255, 255, 255)), color-stop(60%, rgb(255, 255, 255)), color-stop(80%, rgb(206, 206, 206)));\n  background: linear-gradient(to right, rgb(206, 206, 206) 20%, rgb(255, 255, 255) 40%, rgb(255, 255, 255) 60%, rgb(206, 206, 206) 80%);\n  background-size: 200% auto;\n  color: #000;\n  background-clip: text;\n  text-fill-color: transparent;\n  -webkit-background-clip: text;\n  -webkit-text-fill-color: transparent;\n  -webkit-animation: shine 1.5s linear infinite;\n  animation: shine 1.5s linear infinite;\n}\n\n.phone-desc {\n  font-weight: normal;\n  font-size: 14px;\n  color: #727272;\n}\n\n.button-wrapper {\n  display: -webkit-box;\n  display: -ms-flexbox;\n  display: flex;\n  -webkit-box-orient: horizontal;\n  -webkit-box-direction: reverse;\n  -ms-flex-direction: row-reverse;\n  flex-direction: row-reverse;\n  gap: 0.5rem;\n}\n\n.button {\n  height: 40px;\n  width: 40px;\n  max-width: 40px;\n  max-height: 40px;\n  position: relative;\n  border-radius: 100%;\n}\n\n.button:hover {\n  cursor: auto;\n}\n\n.button svg {\n  height: 20px;\n  width: 20px;\n  margin: auto;\n  transform: translateX(10px)translateY(10px);\n  fill: #fff;\n}\n\n.deny {\n  background-color: #ec5445;\n}\n\n.deny svg {\n  -webkit-transform: translateX(7px)translateY(10px) rotate(136deg) translate(-10%, -15%);\n  -ms-transform: translateX(7px)translateY(10px) rotate(136deg) translate(-10%, -15%);\n  transform: translateX(7px)translateY(10px) rotate(136deg) translate(-10%, -15%);\n}\n\n.allow {\n  background-color: #68cd66;\n}\n\n.form-card {\n  width: 280px;\n  height: 350px;\n  border-radius: 1.2rem;\n  background-color: #fff;\n  padding: 1.3rem;\n  color: #212121;\n  text-align: center;\n  position: relative;\n}\n\n.form-card-title {\n  font-size: 1.6rem;\n  margin-bottom: 0.6rem;\n  margin-top: 0.2rem;\n}\n\n.form-card-prompt {\n  margin-bottom: 2rem;\n  font-size: 14px;\n}\n/* hard reset */\n.form-card-input {\n  all: unset;\n}\n\n.form-card-input-wrapper {\n  position: relative;\n  width: 100%;\n  height: 3rem;\n  display: -webkit-box;\n  display: -ms-flexbox;\n  display: flex;\n  margin-bottom: 1rem;\n}\n\n.form-card-input {\n  font-size: 2rem;\n  font-weight: bold;\n  letter-spacing: 2rem;\n  text-align: start;\n  -webkit-transform: translateX(36px);\n  -ms-transform: translateX(36px);\n  transform: translateX(36px);\n  position: absolute;\n  z-index: 3;\n  background-color: transparent;\n}\n\n.form-card-input-bg {\n  content: '';\n  width: 240px;\n  height: 60px;\n  margin: auto;\n  inset: 0;\n  bottom: 10px;\n  position: absolute;\n  z-index: 1;\n  border-radius: 12px;\n  background-color: rgba(206, 206, 206, 0.664);\n}\n\n.call-again {\n  color: #5e5e5e;\n  font-size: 14px;\n}\n\n.call-again:hover {\n  cursor: pointer;\n}\n\n.underlined {\n  text-decoration: underline;\n}\n\n.form-card-submit {\n  position: absolute;\n  width: 180px;\n  margin: auto;\n  color: white;\n  border: none;\n  background-color: #212121;\n  font-size: 1.2rem;\n  border-radius: 0.8rem;\n  padding: 0.8rem 3.5rem;\n  bottom: 2rem;\n  left: 0;\n  right: 0;\n  -webkit-transition: 200ms ease-in-out;\n  transition: 200ms ease-in-out;\n}\n\n.form-card-submit:hover {\n  cursor: pointer;\n  opacity: 0.8;\n}\n\n.form-card-submit:active {\n  opacity: 0.9;\n  -webkit-transform: scale(95%);\n  -ms-transform: scale(95%);\n  transform: scale(95%);\n}\n\n#uuid-d8a0d861-3741-4013 {\n  width: auto;\n  height: 500px;\n}\n\n@-webkit-keyframes scale-out {\n  0%, 15%, 100% {\n    color: #fff;\n    -webkit-transform: scale(72%);\n    transform: scale(72%);\n  }\n\n  16%, 98% {\n    color: rgba(255, 255, 255, 0.295);\n    -webkit-transform: scale(100%);\n    transform: scale(100%);\n  }\n}\n\n@keyframes scale-out {\n  0%, 15%, 100% {\n    color: #fff;\n    -webkit-transform: scale(72%);\n    transform: scale(72%);\n  }\n\n  16%, 98% {\n    color: rgba(255, 255, 255, 0.295);\n    -webkit-transform: scale(100%);\n    transform: scale(100%);\n  }\n}\n\n@-webkit-keyframes shine {\n  to {\n    background-position: 200% center;\n  }\n}\n\n@keyframes shine {\n  to {\n    background-position: 200% center;\n  }\n}"
