    "animationLevel": "high",
    "html": "<form class=\"form\">\n      <p class=\"login\">Log in to Twitter</p>\n      <div class=\"inputContainer\">\n        <input type=\"button\" value=\"next\" class=\"submit\">\n        <input placeholder=\"phone or email or username\" type=\"text\" class=\"fInput email\">\n        <input placeholder=\"Enter your password\" type=\"text\" class=\"fInput pass\">\n      </div>\n      <button class=\"forget\">forget password?</button>\n      <div class=\"con\">\n        <p>don't have account?&nbsp;</p>\n        <a href=\"#\"> sign in</a>\n      </div>\n    </form>",
    "css": "/* From Uiverse.io by omar-alghaish - Tags: login, twitter, form */\n.form {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  flex-direction: column;\n  position: relative;\n  width: 400px;\n  padding: 50px;\n  height: 500px;\n  background-color: rgb(0, 0, 0);\n  border-radius: 10px;\n}\n\n.inputContainer {\n  background-color: rgba(255, 0, 0, 0);\n  position: relative;\n  width: 100%;\n  height: 50px;\n}\n\n.fInput {\n  width: 100%;\n  height: 50px;\n  border-radius: 3px;\n  border: 1px solid rgb(48, 45, 45);\n  background-color: black;\n  padding: 10px;\n  color: white;\n  transition: .1s;\n  position: absolute;\n}\n\n.fInput:focus {\n  border: 1px rgb(0, 136, 255) solid;\n  outline: none;\n}\n\n.fInput:focus::placeholder {\n  color: rgb(0, 136, 255);\n}\n\n.fInput.email {\n  z-index: 1;\n}\n\n.fInput.pass:focus {\n  z-index: 2;\n}\n\n.submit {\n  width: 100%;\n  top: 60px;\n  padding: 7px 0;\n  border-radius: 20px;\n  cursor: pointer;\n  transition: .3s;\n  position: absolute;\n}\n\n.submit:focus + .email {\n  display: none;\n}\n\n.login {\n  width: 100%;\n  color: white;\n  font-family: sans-serif;\n  font-weight: 700;\n  font-size: 20px;\n  padding: 30px 0;\n  position: absolute;\n  top: 90px;\n  left: 55px\n}\n\n.submit:hover {\n  opacity: .9;\n}\n\n.forget {\n  width: 100%;\n  background-color: transparent;\n  color: white;\n  border: 1PX solid rgba(255, 255, 255, 0.151);\n  margin-top: 15px;\n  padding: 7px 0;\n  border-radius: 20px;\n  cursor: pointer;\n  transition: .3s;\n  margin-top: 50px;\n}\n\n.forget:hover {\n  background-color: rgba(255, 255, 255, 0.151);\n}\n\n.con {\n  display: flex;\n  justify-content: flex-start;\n  width: 100%;\n  margin-top: 30px;\n  color: rgb(111, 103, 103);\n  font-size: 13px;\n  font-family: sans-serif;\n  background-color: rgba(255, 0, 0, 0);\n}\n\n.con a {\n  color: rgb(0, 136, 255);\n}"
