    "animationLevel": "high",
    "html": "<div class=\"form-container\">\n    <p>Login</p>\n<form class=\"form\">\n    <label>Email</label>\n    <input type=\"text\" class=\"input\" placeholder=\"Enter yout email\">\n    <label>Password</label>\n    <input type=\"password\" class=\"input\" placeholder=\"Password\"> \n    <button>Submit</button>\n</form>\n</div>",
    "css": "/* From Uiverse.io by omar-alghaish - Tags: login, form */\n.form-container {\n  width: 300px;\n  background: linear-gradient(180deg,rgb(0, 183, 255) 25%,rgb(255, 255, 255) 20%);\n  height: 350px;\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n  align-items: center;\n  position: relative;\n}\n\n.form {\n  width: 80%;\n  display: flex;\n  flex-direction: column;\n  margin-top: 40px;\n}\n\n.form-container p {\n  position: absolute;\n  top: 10%;\n  left: 10%;\n  font-size: 30px;\n  font-weight: 900;\n  color: rgb(255, 255, 255);\n}\n\n.form-container label {\n  color: rgb(40, 42, 44);\n  margin-top: 15px;\n  margin-bottom: 5px;\n  font-size: 15px;\n}\n\n.form-container .input {\n  padding: 10px;\n  height: 35px;\n  border: none;\n  background-color: rgb(224, 231, 236);\n}\n\n.form-container .input:focus {\n  outline: none;\n}\n\n.form-container button {\n  border: none;\n  height: 35px;\n  margin-top: 30px;\n  background-color: rgb(0, 183, 255);\n  color: white;\n  font-size: 16px;\n}"
