    "animationLevel": "high",
    "html": "<form class=\"form\">\n  <header>\n    Credit card information\n  <span class=\"message\">Fill the form to continue.</span>\n  </header>\n  <label>\n    <span>Card Number</span>\n    <input placeholder=\"Type your card number\" class=\"input\" type=\"number\" required=\"\">\n  </label>\n  <label>\n    <span>Name on card</span>\n    <input placeholder=\"Type your name as appear on card\" class=\"input\" type=\"text\" required=\"\">\n  </label>\n  <fieldset>\n    <label class=\"sm\">\n    <span>Exp. Month</span>\n    <div class=\"custom-select\">\n    <select class=\"input\" type=\"select\" required=\"\">\n      <option></option>\n      <option>January</option>\n      <option>February</option>\n      <option>March</option>\n      <option>April</option>\n      <option>May</option>\n      <option>June</option>\n      <option>July</option>\n      <option>August</option>\n      <option>September</option>\n      <option>October</option>\n      <option>November</option>\n      <option>Dicember</option>\n    </select>\n    </div>\n  </label>\n  <label class=\"sm\">\n    <span>Exp. Year </span>\n    <div class=\"custom-select\">\n    <select class=\"input\" type=\"select\" required=\"\">\n      <option></option>\n      <option>2023</option>\n      <option>2024</option>\n      <option>2025</option>\n      <option>2026</option>\n\n    </select>\n    </div>\n  </label>\n    <label class=\"sm\">\n    <span>CW </span>   \n    <input class=\"input\" placeholder=\"1234\" size=\"4\" maxlength=\"4\" type=\"text\" required=\"\">\n  </label>\n  </fieldset>\n  <div class=\"submitCard\">\n    <button>Complete payment</button>\n  </div>\n</form>",
    "css": "/* From Uiverse.io by roroland - Tags: form */\n/* Initial form state */\n.form {\n  --col1: #fff;\n  --col2: #252325;\n  --col3: rgba(232, 213, 196, 0.9);\n  --col4: #ffffff;\n  --col5: #683363;\n  --sh: rgba(80, 80, 80, 0.35);\n  --rad: 4px;\n  --radBig: 10px;\n  border-radius: 0 0 var(--radBig) var(--radBig);\n  box-shadow: 0 0 20px var(--sh);\n  display: flex;\n  flex-direction: column;\n  gap: 1.5em 1em;\n  padding: 1em;\n  position: relative;\n  max-width: 75%;\n  max-height: 90px;\n  transition: background .3s ease-out, max-height .3s ease-out;\n  overflow: hidden;\n}\n\n.form::before {\n  content: 'Ready to purchase?';\n  color: var(--col2);\n  font-size: 1.2em;\n  font-weight: 700;\n  display: grid;\n  width: calc(100% - 2em);\n  height: 60%;\n  position: absolute;\n  place-items: center;\n  z-index: 99999;\n}\n\n.form::after {\n  content: '';\n  backdrop-filter: blur(6px) grayscale(100%);\n  background: linear-gradient(-180deg, rgba(255,255,255,1) 0%, rgba(255,255,255,.5) 70%, rgba(255, 255, 255, 0.3) 90%);\n  height: 100%;\n  width: 100%;\n  left: 0;\n  top: 0;\n  display: block;\n  position: absolute;\n  z-index: 999;\n}\n\n.form::after,\n.form::before {\n  border-radius: 0 0 var(--radBig) var(--radBig);\n  pointer-events: none;\n  transition: all .5s ease-out;\n}\n\n/* Form hover and focus */\n.form:hover,\n.form:focus-within {\n  max-width: 100%;\n  max-height: 380px;\n}\n\n.form:focus-within {\n  overflow: initial;\n}\n\n.form:hover::before,\n.form:hover::after {\n  opacity: 0;\n}\n\n.form:hover::after {\n  backdrop-filter: blur(0) grayscale(0%);\n}\n\n.form header {\n  color: var(--col1);\n  font-size: 1.25rem;\n  font-weight: 600;\n}\n/* Labels and inputs UI */\n:is(.form) label span, label input {\n  flex: 1 100%;\n  transition: all .3s ease-out;\n}\n\n:is(.form) input, select, button {\n  appearance: none;\n  border: 0;\n  padding: .75em;\n  border-radius: var(--rad);\n  transition: all .3s ease-out;\n}\n\n.form label {\n  display: flex;\n  flex-flow: row wrap;\n  color: var(--col4);\n  gap: .5em;\n}\n\n.form input {\n  box-shadow: inset 3px 3px 1px var(--sh);\n}\n\n.form fieldset {\n  display: flex;\n  backdrop-filter: blur(10px);\n  flex-flow: row nowrap;\n  gap: 1em;\n  position: relative;\n  transition: all .3s ease-out;\n  padding: 1rem;\n  z-index: 10;\n  border: 3px double var(--col1);\n  border-radius: var(--rad);\n}\n\n.form fieldset label {\n  flex: 1;\n  display: flex;\n  flex-flow: row wrap;\n  font-size: .75em;\n}\n\n.sm {\n  justify-content: space-around;\n}\n\n.sm span {\n  text-align: center;\n}\n\n.form select {\n  box-shadow: inset 3px 3px 1px var(--sh);\n  padding: .75em 1.75em .75em 0.5em;\n  position: relative;\n}\n\n.custom-select {\n  position: relative;\n}\n\n.custom-select::after {\n  position: absolute;\n  content: \"\";\n  top: 45%;\n  right: 5px;\n  width: 0;\n  height: 0;\n  border: 6px solid transparent;\n  border-color: var(--col5) transparent transparent transparent;\n}\n\n.form fieldset span {\n  flex: 1 100%;\n}\n\n.form fieldset input {\n  flex: 0 1 40px;\n}\n\n.form button {\n  background-color: var(--col1);\n  color: var(--col4);\n  border: 2px solid var(--col4);\n  font-size: 1em;\n  font-weight: 700;\n  align-self: center;\n  padding: .5em 1.5em;\n  appearance: none;\n}\n\n/* Form and UI valid and invalid states */\n.form input:focus,\n.form select:focus {\n  outline: 3px solid var(--col3);\n  outline-offset: 1px;\n}\n\n.form input:invalid:not(:focus),\n.form select:invalid:not(:focus) {\n  background-color: var(--col3);\n  outline: 3px solid var(--col4);\n  outline-offset: 1px;\n}\n\n.form input:valid:not(:focus),\n.form select:valid:not(:focus) {\n  outline: 3px solid var(--col1);\n  outline-offset: 1px;\n}\n\n.form .message {\n  display: block;\n  opacity: 0;\n  font-size: .75em;\n  font-weight: 400;\n  transition: all .3s ease-out;\n  margin: -1rem 0 0;\n}\n\n.form:has(:invalid) .message {\n  opacity: 1;\n  margin: .25rem 0 0 0;\n}\n\nlabel:has(input:invalid),\nlabel:has(select:invalid) {\n  color: var(--col3);\n  opacity: .8;\n}\n\nlabel:has(input:valid),\nlabel:has(select:valid) {\n  opacity: 1;\n}\n\n.form:hover:has(:focus, :active):valid .submitCard {\n  max-height: 180px;\n  opacity: 1;\n  transition: opacity 1s ease-out .5s, translate 1.3s ease-out;\n  translate: 0 100%;\n}\n\n.form:hover:invalid {\n  transition: all .3s ease-out;\n  background-color: var(--col5);\n}\n\n.form:hover:valid {\n  transition: all .3s ease-out;\n  background-color: var(--col1);\n}\n\n.form:hover:valid * {\n  color: var(--col2);\n}\n\n.form:hover:valid input,\n.form:hover:valid select {\n  outline: 3px solid var(--col2);\n}\n\n.form:hover:invalid fieldset {\n  border: 1px dashed var(--col3);\n}\n\n.form:hover:valid fieldset {\n  border: 1px dashed var(--col2);\n}\n\n/* Submit block */\n.form .submitCard {\n  display: flex;\n  justify-content: center;\n  background-color: var(--col2);\n  border-radius: 0 0 var(--rad) var(--rad);\n  bottom: 0;\n  padding: .5em;\n  opacity: 0;\n  max-height: 0;\n  translate: 0 -100%;\n  position: absolute;\n  width: calc(100% - 2em);\n  transition: all .5s ease-out .1s;\n  z-index: -1;\n}"
