    "css": "/* From Uiverse.io by sameer2malik - Tags: glassmorphism, blur filter, gradients */\n.container {\n  display: flex;\n  width: 520px;\n  height: 500px;\n  max-width: 99%;\n  align-items: center;\n  justify-content: center;\n  position: relative;\n  overflow: hidden;\n  background-color: #ffffff25;\n  border-radius: 15px;\n  box-shadow: 0px 0px 30px rgba(0, 0, 0, 0.03);\n  border: 0.1px solid rgba(128, 128, 128, 0.178);\n}\n\n.left {\n  width: 66%;\n  height: 100%;\n}\n\n.form {\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n  height: 100%;\n  width: 100%;\n  left: 0;\n  backdrop-filter: blur(20px);\n  position: relative;\n}\n\n.form::before {\n  position: absolute;\n  content: \"\";\n  width: 40%;\n  height: 40%;\n  right: 1%;\n  z-index: -1;\n  background: radial-gradient(\n    circle,\n    rgb(194, 13, 170) 20%,\n    rgb(26, 186, 235) 60%,\n\n    rgb(26, 186, 235) 100%\n  );\n  filter: blur(70px);\n  border-radius: 50%;\n}\n\n.right {\n  width: 34%;\n  height: 100%;\n}\n\n.img {\n  width: 100%;\n  height: 100%;\n}\n\n.container::after {\n  position: absolute;\n  content: \"\";\n  width: 80%;\n  height: 80%;\n  right: -40%;\n  background: rgb(157, 173, 203);\n  background: radial-gradient(\n    circle,\n    rgba(157, 173, 203, 1) 61%,\n    rgba(99, 122, 159, 1) 100%\n  );\n  border-radius: 50%;\n  z-index: -1;\n}\n\n.input,\nbutton {\n  background: rgba(253, 253, 253, 0);\n  outline: none;\n  border: 1px solid rgba(255, 0, 0, 0);\n  border-radius: 0.5rem;\n  padding: 10px;\n  margin: 10px auto;\n  width: 80%;\n  display: block;\n  color: #425981;\n  font-weight: 500;\n  font-size: 1.1em;\n}\n\n.input-block {\n  position: relative;\n}\n\nlabel {\n  position: absolute;\n  left: 15%;\n  top: 37%;\n  pointer-events: none;\n  color: gray;\n}\n\n.forgot {\n  display: block;\n  margin: 5px 0 10px 0;\n  margin-left: 35px;\n  color: #5e7eb6;\n  font-size: 0.9em;\n}\n\n.input:focus + label,\n.input:valid + label {\n  transform: translateY(-120%) scale(0.9);\n  transition: all 0.4s;\n}\n\nbutton {\n  background-color: #5e7eb6;\n  color: white;\n  font-size: medium;\n  box-shadow: 2px 4px 8px rgba(70, 70, 70, 0.178);\n}\n\na {\n  color: #5e7eb6;\n}\n\n.input {\n  box-shadow: inset 4px 4px 4px rgba(165, 163, 163, 0.315),\n    4px 4px 4px rgba(218, 218, 218, 0.13);\n}"
