    "html": "<div class=\"container\">\n      <div class=\"nav-bar\">\n      \t<a>Chat</a>\n        <div class=\"close\">\n         \t<div class=\"line one\"></div>\n         \t<div class=\"line two\"></div>\n        </div>\n      </div>\n      <div class=\"messages-area\">\n        \n        <div class=\"message one\"></div>\n        <div class=\"message two\"></div>\n        <div class=\"message three\"></div>\n        <div class=\"message four\"></div>\n        <div class=\"message five\"></div>\n        <div class=\"message six\"></div>\n      </div>\n      <div class=\"sender-area\">\n        <div class=\"input-place\">\n        \t<input placeholder=\"Send a message.\" class=\"send-input\" type=\"text\">\n            <div class=\"send\">\n\t\t\t\t<svg class=\"send-icon\" version=\"1.1\" id=\"Capa_1\" xmlns=\"http://www.w3.org/2000/svg\" xmlns:xlink=\"http://www.w3.org/1999/xlink\" x=\"0px\" y=\"0px\" viewBox=\"0 0 512 512\" style=\"enable-background:new 0 0 512 512;\" xml:space=\"preserve\"><g><g><path fill=\"#6B6C7B\" d=\"M481.508,210.336L68.414,38.926c-17.403-7.222-37.064-4.045-51.309,8.287C2.86,59.547-3.098,78.551,1.558,96.808 L38.327,241h180.026c8.284,0,15.001,6.716,15.001,15.001c0,8.284-6.716,15.001-15.001,15.001H38.327L1.558,415.193 c-4.656,18.258,1.301,37.262,15.547,49.595c14.274,12.357,33.937,15.495,51.31,8.287l413.094-171.409 C500.317,293.862,512,276.364,512,256.001C512,235.638,500.317,218.139,481.508,210.336z\"></path></g></g></svg>\n        \t</div>\n      \t</div>\n      </div>\n    <div></div></div>",
    "css": "/* From Uiverse.io by shadowmurphy - Tags: form, message, arrow, chat, chatgpt, close, colors */\n.container {\n  width: 300px;\n  height: 320px;\n  background-color: #343541;\n  border-radius: 8px;\n  display: flex;\n  flex-direction: column;\n}\n\n.nav-bar {\n  width: 100%;\n  height: 40px;\n  background-color: none;\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n}\n\n.nav-bar a {\n  color: #6B6C7B;\n  white-space: nowrap;\n  margin-left: 10px;\n  user-select: none;\n}\n\n.close {\n  width: 40px;\n  height: 40px;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  position: relative;\n  cursor: pointer;\n}\n\n.line {\n  position: absolute;\n  width: 20px;\n  height: 3px;\n  background-color: #6B6C7B;\n  border-radius: 30px;\n}\n\n.line.one {\n  transform: rotate(45deg)\n}\n\n.line.two {\n  transform: rotate(135deg)\n}\n\n.messages-area {\n  background-color: green;\n  width: 100%;\n  height: 210px;\n}\n\n.sender-area {\n  background-color: #343541;\n  width: 100%;\n  height: 70px;\n  display: flex;\n  border-radius: 8px;\n}\n\n.message {\n  width: 100%;\n  height: 40px;\n}\n\n.message.one,\n.message.three,\n.message.five {\n  background-color: #2E2F3A;\n}\n\n.message.two,\n.message.four,\n.message.six {\n  background-color: #343541;\n}\n\n.send-img {\n  width: 30px;\n}\n\n.send-input {\n  outline: none;\n  display: flex;\n  border: none;\n  background: none;\n  height: 40px;\n  width: 230px;\n  border-radius: 7px;\n  background: none;\n  color: white;\n  text-overflow: ellipsis;\n  white-space: nowrap;\n  overflow: hidden;\n  margin-left: 5px;\n}\n\n.send-input::placeholder {\n  color: #828E9E;\n}\n\n.input-place {\n  display: flex;\n  flex-direction: row;\n  margin-top: 15px;\n  margin-left: 10px;\n  align-items: center;\n  background-color: #40414F;\n  border-radius: 7px;\n  height: 40px;\n  width: 280px;\n  gap: 5px;\n  border: 1px solid #2E2F3A;\n}\n\n.send {\n  width: 30px;\n  height: 30px;\n  background-color: none;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  cursor: pointer;\n}\n\n.send-icon {\n  width: 17px;\n}"
