    "html": "<!-- From Uiverse.io by themrsami  - Tags: form, tailwindcss, signup form, facebook clone signup -->\n<div class=\"mx-auto max-w-[432px] bg-white rounded-md shadow-lg drop-shadow-md\">\n  <div class=\"px-4 py-3 flex justify-between\">\n    <div>\n      <h2 class=\"font-bold\" style=\"font-size: 32px\">Sign Up</h2>\n      <p class=\"text-gray-500\" style=\"font-size: 15px\">It's quick and easy.</p>\n    </div>\n    <div style=\"cursor: pointer\" class=\"text-gray-600\">\n      <svg\n        xmlns=\"http://www.w3.org/2000/svg\"\n        class=\"h-7 w-7\"\n        fill=\"none\"\n        viewBox=\"0 0 24 24\"\n        stroke=\"currentColor\"\n      >\n        <path\n          stroke-linecap=\"round\"\n          stroke-linejoin=\"round\"\n          stroke-width=\"3\"\n          d=\"M6 18L18 6M6 6l12 12\"\n        ></path>\n      </svg>\n    </div>\n  </div>\n  <hr class=\"bg-gray-600\" />\n  <div class=\"px-4 pt-3 pb-6 space-y-3\">\n    <div class=\"space-x-3 flex\">\n      <input\n        type=\"text\"\n        placeholder=\"First name\"\n        class=\"flex-1 ring-1 ring-gray-400 rounded-md text-md px-2 py-2 outline-none bg-gray-100 focus:placeholder-gray-500\"\n      />\n      <input\n        type=\"text\"\n        placeholder=\"Surname\"\n        class=\"flex-1 ring-1 ring-gray-400 rounded-md text-md px-2 py-2 outline-none bg-gray-100 focus:placeholder-gray-500\"\n      />\n    </div>\n    <div>\n      <input\n        type=\"text\"\n        placeholder=\"Mobile number or email address\"\n        class=\"w-full ring-1 ring-gray-400 rounded-md text-md px-2 py-2 outline-none bg-gray-100 focus:placeholder-gray-500\"\n      />\n    </div>\n    <div>\n      <input\n        type=\"password\"\n        placeholder=\"New password\"\n        class=\"w-full ring-1 ring-gray-400 rounded-md text-md px-2 py-2 outline-none bg-gray-100 focus:placeholder-gray-500\"\n      />\n    </div>\n    <div>\n      <div class=\"text-gray-500\" style=\"font-size: 12px;\">\n        Date of birth <a href=\"\"> (?) </a>\n      </div>\n      <div class=\"mt-1 flex space-x-3\">\n        <select\n          name=\"day\"\n          class=\"text-md flex-1 px-1 py-1.5 ring-1 ring-gray-400 rounded-md outline-none\"\n        >\n          <option>1</option>\n          <option>2</option>\n          <option>3</option>\n          <option>4</option>\n          <option>5</option>\n          <option>6</option>\n          <option>7</option>\n          <option>8</option>\n          <option>9</option>\n          <option>10</option>\n          <option>11</option>\n          <option>12</option>\n          <option>13</option>\n          <option>14</option>\n          <option>15</option>\n          <option>16</option>\n          <option>17</option>\n          <option>18</option>\n          <option>19</option>\n          <option>20</option>\n          <option>21</option>\n          <option>22</option>\n          <option>23</option>\n          <option>24</option>\n          <option>25</option>\n          <option>26</option>\n          <option>27</option>\n          <option>28</option>\n          <option>29</option>\n          <option>30</option>\n          <option>31</option>\n        </select>\n        <select\n          name=\"month\"\n          class=\"text-md flex-1 px-1 py-1.5 ring-1 ring-gray-400 rounded-md outline-none\"\n        >\n          <option>January</option>\n          <option>February</option>\n          <option>March</option>\n          <option>April</option>\n          <option>May</option>\n          <option>June</option>\n          <option>July</option>\n          <option>August</option>\n          <option>September</option>\n          <option>October</option>\n          <option>November</option>\n          <option>December</option>\n        </select>\n        <select\n          name=\"year\"\n          class=\"text-md flex-1 px-1 py-1.5 ring-1 ring-gray-400 rounded-md outline-none\"\n        >\n          <option>1990</option>\n          <option>1991</option>\n          <option>1992</option>\n          <option>1993</option>\n          <option>1994</option>\n          <option>1995</option>\n          <option>1996</option>\n          <option>1997</option>\n          <option>1998</option>\n          <option>1999</option>\n          <option>2000</option>\n          <option>2001</option>\n          <option>2002</option>\n          <option>2003</option>\n          <option>2004</option>\n          <option>2005</option>\n          <option>2006</option>\n          <option>2007</option>\n          <option>2008</option>\n          <option>2009</option>\n          <option>2010</option>\n          <option>2011</option>\n          <option>2012</option>\n          <option>2013</option>\n          <option>2014</option>\n          <option>2015</option>\n          <option>2016</option>\n          <option>2017</option>\n          <option>2018</option>\n          <option>2019</option>\n          <option>2020</option>\n          <option>2021</option>\n          <option>2022</option>\n          <option>2023</option>\n        </select>\n      </div>\n    </div>\n    <div>\n      <div class=\"text-gray-500\" style=\"font-size: 12px;\">\n        Gender <a href=\"\"> (?) </a>\n      </div>\n      <div class=\"mt-1 flex space-x-3\">\n        <label\n          for=\"female\"\n          class=\"flex-1 flex space-x-2 justify-between items-center rounded-md px-2 py-1 border border-gray-400\"\n        >\n          <span>Female</span>\n          <input type=\"radio\" id=\"female\" name=\"gender\" />\n        </label>\n        <label\n          for=\"male\"\n          class=\"flex-1 flex space-x-2 justify-between items-center rounded-md px-2 py-1 border border-gray-400\"\n        >\n          <span>Male</span>\n          <input type=\"radio\" id=\"male\" name=\"gender\" />\n        </label>\n        <label\n          for=\"other\"\n          class=\"flex-1 flex space-x-2 justify-between items-center rounded-md px-2 py-1 border border-gray-400\"\n        >\n          <span>Custom</span>\n          <input type=\"radio\" id=\"other\" name=\"gender\" />\n        </label>\n      </div>\n    </div>\n    <div>\n      <p class=\"text-gray-600\" style=\"font-size: 11px\">\n        People who use our service may have uploaded your contact information to\n        Facebook.\n        <a href=\"\" class=\"hover:text-blue-900 font-medium hover:underline\"\n          >Learn more</a\n        >.\n      </p>\n      <p class=\"text-gray-600 mt-4\" style=\"font-size: 11px\">\n        By clicking Sign Up, you agree to our\n        <a href=\"\" class=\"hover:text-blue-900 font-medium hover:underline\"\n          >Terms</a\n        >,\n        <a href=\"\" class=\"hover:text-blue-900 font-medium hover:underline\"\n          >Privacy Policy</a\n        >\n        and\n        <a href=\"\" class=\"hover:text-blue-900 font-medium hover:underline\"\n          >Cookies Policy</a\n        >. You may receive SMS notifications from us and can opt out at any\n        time.\n      </p>\n    </div>\n    <div class=\"text-center\">\n      <button\n        class=\"text-white font-bold px-16 py-1 rounded-md\"\n        style=\"background-color: #00A400; font-size: 18px;\"\n      >\n        Sign Up\n      </button>\n    </div>\n  </div>\n</div>",
