    "css": "/* From Uiverse.io by vinodjangid07 - Tags: form, discount */\n.discountForm {\n  width: 250px;\n  height: 300px;\n  background-color: rgb(255, 255, 255);\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  padding: 20px 30px;\n  gap: 20px;\n  position: relative;\n  box-shadow: 0px 0px 20px rgba(0, 0, 0, 0.082);\n}\n\n.DiscountHeading {\n  font-size: 1.5em;\n  color: rgb(15, 15, 15);\n  font-weight: 700;\n}\n\n.DiscountSubheading {\n  font-size: 0.8em;\n  color: black;\n  text-align: center;\n}\n\n.inputContainer {\n  width: 100%;\n  display: flex;\n  flex-direction: column;\n  gap: 10px;\n}\n\n#email-address {\n  height: 30px;\n  width: 100%;\n  border: 1px solid rgb(228, 228, 228);\n  background-color: white;\n  padding: 0px 10px;\n  outline: none;\n  text-align: center;\n}\n\n.submitButton {\n  width: 100%;\n  height: 30px;\n  border: none;\n  background-color: rgb(15, 15, 15);\n  color: white;\n  font-weight: 600;\n  cursor: pointer;\n}\n\n.submitButton:hover {\n  background-color: rgb(36, 36, 36);\n}\n\n.exitBtn {\n  position: absolute;\n  top: 5px;\n  right: 5px;\n  box-shadow: 0px 0px 20px rgba(0, 0, 0, 0.171);\n  background-color: rgb(255, 255, 255);\n  border-radius: 50%;\n  width: 25px;\n  height: 25px;\n  border: none;\n  color: black;\n  font-size: 1.1em;\n  cursor: pointer;\n}"
